// OAuth 2.0 Authorization Server Metadata (RFC 8414)
// Claude.ai discovers your OAuth config via /.well-known/oauth-authorization-server
import { Hono } from "hono";
const app = new Hono();

app.get("/.well-known/oauth-authorization-server", (c) => {
  const base = new URL(c.req.url).origin;
  return c.json({
    issuer: base,
    authorization_endpoint: `${base}/oauth/authorize`,
    token_endpoint: `${base}/oauth/token`,
    response_types_supported: ["code"],
    grant_types_supported: ["authorization_code", "refresh_token"],
    code_challenge_methods_supported: ["S256"],  // PKCE required
    scopes_supported: ["mcp:tools", "mcp:resources"],
  });
});

app.get("/oauth/authorize", (c) => {
  const { redirect_uri, state, code_challenge, code_challenge_method } = c.req.query();
  // Forward to upstream OAuth provider (e.g., Atlassian, GitHub, Google)
  const upstream = new URL("https://auth.atlassian.com/authorize");
  upstream.searchParams.set("client_id", process.env.CLIENT_ID!);
  upstream.searchParams.set("redirect_uri", redirect_uri);
  upstream.searchParams.set("response_type", "code");
  upstream.searchParams.set("scope", "read:jira-work write:jira-work");
  upstream.searchParams.set("state", state);
  upstream.searchParams.set("code_challenge", code_challenge);
  upstream.searchParams.set("code_challenge_method", "S256");
  return c.redirect(upstream.toString());
});
